"use strict";(self.webpackChunkutm_doc=self.webpackChunkutm_doc||[]).push([[4743],{8240:e=>{e.exports=JSON.parse('{"tag":{"label":"clippings","permalink":"/en/tags/clippings","allTagsPath":"/en/tags","count":2,"items":[{"id":"Algorithm_Development/SIMULATOR/SITL/Gazebo/Docs/\u5173\u4e8eGazebo","title":"About -- Gazebo","description":"What is Gazebo and its history.","permalink":"/en/Algorithm_Development/SIMULATOR/SITL/Gazebo/Docs/\u5173\u4e8eGazebo"},{"id":"Algorithm_Development/RL/ChampionLevelDroneRacing/\u4f7f\u7528\u6df1\u5ea6\u5f3a\u5316\u5b66\u4e60\u7684\u51a0\u519b\u7ea7Swift\u65e0\u4eba\u673a\u7ade\u901f\u7cfb\u7edf","title":"\u4f7f\u7528\u6df1\u5ea6\u5f3a\u5316\u5b66\u4e60\u7684\u51a0\u519b\u7ea7Swift\u65e0\u4eba\u673a\u7ade\u901f\u7cfb\u7edf","description":"First-person view (FPV) drone racing is a televised sport in which professional competitors pilot high-speed aircraft through a 3D circuit. Each pilot sees the environment from the perspective of their drone by means of video streamed from an onboard camera. Reaching the level of professional pilots with an autonomous drone is challenging because the robot needs to fly at its physical limits while estimating its speed and location in the circuit exclusively from onboard sensors1. Here we introduce Swift, an autonomous system that can race physical vehicles at the level of the human world champions. The system combines deep reinforcement learning (RL) in simulation with data collected in the physical world. Swift competed against three human champions, including the world champions of two international leagues, in real-world head-to-head races. Swift won several races against each of the human champions and demonstrated the fastest recorded race time. This work represents a milestone for mobile robotics and machine intelligence2, which may inspire the deployment of hybrid learning-based solutions in other physical systems. An autonomous system is described that combines deep reinforcement learning with onboard sensors collecting data from the physical world, enabling it to fly faster than human world champion drone pilots around a race track.","permalink":"/en/Algorithm_Development/RL/ChampionLevelDroneRacing/\u4f7f\u7528\u6df1\u5ea6\u5f3a\u5316\u5b66\u4e60\u7684\u51a0\u519b\u7ea7Swift\u65e0\u4eba\u673a\u7ade\u901f\u7cfb\u7edf"}],"unlisted":false}}')}}]);